const CHECKS = {
  telegram: {
    env: ['TELEGRAM_BOT_TOKEN', 'APPROVAL_CHAT_ID'],
    instructions: 'Set TELEGRAM_BOT_TOKEN and APPROVAL_CHAT_ID in your n8n environment, and ensure the Telegram Bot credential is configured.'
  },
  whatsapp: {
    env: ['EVOLUTION_API_URL', 'EVOLUTION_API_KEY', 'EVOLUTION_INSTANCE_NAME', 'WHATSAPP_PHONE'],
    instructions: 'Set EVOLUTION_API_URL, EVOLUTION_API_KEY, EVOLUTION_INSTANCE_NAME, and WHATSAPP_PHONE in your n8n environment.'
  },
  deepseek: {
    env: ['DEEPSEEK_API_KEY'],
    instructions: 'Set DEEPSEEK_API_KEY in your n8n environment and configure the DeepSeek credential.'
  }
};

const capability = $input.item.json.capability;
if (!capability) {
  return [{ json: { status: 'missing', missingFields: ['capability'], instructions: 'Pass a capability string (telegram|whatsapp|deepseek) as input.' } }];
}

const check = CHECKS[capability];
if (!check) {
  return [{ json: { status: 'missing', missingFields: ['capability'], instructions: `Unknown capability '${capability}'. Valid values: ${Object.keys(CHECKS).join(', ')}.` } }];
}

const missingFields = [];
for (const envVar of check.env) {
  const val = $env[envVar];
  if (!val || val.trim() === '') {
    missingFields.push(envVar);
  }
}

if (missingFields.length > 0) {
  return [{ json: { status: 'missing', missingFields, instructions: check.instructions } }];
}

return [{ json: { status: 'ok', capability, checkedFields: check.env } }];
